"""Send a test hook event to the dashboard's HTTP server."""

import json
import sys
import urllib.request


def main():
    port = int(sys.argv[1]) if len(sys.argv) > 1 else 17384
    session_id = sys.argv[2] if len(sys.argv) > 2 else "test-manual-session"
    event = sys.argv[3] if len(sys.argv) > 3 else "Stop"

    payload = json.dumps({
        "session_id": session_id,
        "hook_event_name": event,
        "tool_name": "",
        "cwd": "/tmp/test",
    }).encode()

    url = f"http://127.0.0.1:{port}/hook"
    print(f"POST {url}")
    print(f"  session_id={session_id} event={event}")

    try:
        req = urllib.request.Request(
            url,
            data=payload,
            headers={"Content-Type": "application/json"},
            method="POST",
        )
        with urllib.request.urlopen(req, timeout=5) as resp:
            print(f"  status={resp.status}")
            print(f"  body={resp.read().decode()}")
    except Exception as exc:
        print(f"  FAILED: {exc}")


if __name__ == "__main__":
    main()
